SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

CREATE OR REPLACE VIEW vm_mem_m_capital_stock_detail (account_year, membership_no, average_return, dividend, drop_dividend, drop_average, total_interest, share_coll_dividend, bf_share_dividend, bf_share_coll_dividend, somtob_amount, total_money_reward, sum_paid, money_type_name, real_item_amount) AS SELECT sc_mem_m_capital_stock_detail.account_year,
         sc_mem_m_capital_stock_detail.membership_no,
         CASE WHEN   sc_mem_m_capital_stock_detail.drop_average ='1' THEN  0   ELSE sc_mem_m_capital_stock_detail.average_return END  as average_return,
         CASE WHEN   sc_mem_m_capital_stock_detail.drop_dividend ='1' THEN  0   ELSE sc_mem_m_capital_stock_detail.dividend END   as dividend ,
         sc_mem_m_capital_stock_detail.drop_dividend,
         sc_mem_m_capital_stock_detail.drop_average,
         sc_mem_m_capital_stock_detail.total_interest,
         0 as  share_coll_dividend,
         sc_mem_m_capital_stock_detail.bf_share_dividend,
         0 as  bf_share_coll_dividend
         ,sc_mem_m_capital_stock_detail.somtob_amount
         ,sc_mem_m_capital_stock_detail.total_money_reward
         , CASE WHEN   sc_mem_m_capital_stock_detail.drop_average ='1' THEN  0   ELSE sc_mem_m_capital_stock_detail.average_return END   + 
           CASE WHEN   sc_mem_m_capital_stock_detail.drop_dividend ='1' THEN  0   ELSE sc_mem_m_capital_stock_detail.dividend END   + 
           total_money_reward
as sum_paid 
,(  SELECT sc_com_m_ucf_money_type.money_type_name  
    FROM sc_mem_m_capital_pay,   
         sc_com_m_ucf_money_type  
    WHERE  sc_mem_m_capital_pay.group_pay_code = sc_com_m_ucf_money_type.money_type_id  and  
          sc_mem_m_capital_pay.account_year = sc_mem_m_capital_stock_detail.account_year  AND  
          sc_mem_m_capital_pay.membership_no = sc_mem_m_capital_stock_detail.membership_no  AND  
          sc_mem_m_capital_pay.ext_status = '0'  ) as money_type_name 
          
,( select coalesce(sc_mem_m_capital_pay.ITEM_AMOUNT , 0)
  from sc_mem_m_capital_pay
  where  sc_mem_m_capital_pay.account_year = sc_mem_m_capital_stock_detail.account_year    
  and sc_mem_m_capital_pay.membership_no = sc_mem_m_capital_stock_detail.membership_no    
  and sc_mem_m_capital_pay.ext_status = '1'
  )as real_item_amount
           
          
    from SC_MEM_M_CAPITAL_STOCK_DETAIL
   WHERE sc_mem_m_capital_stock_detail.ending_balance > 0
   and sc_mem_m_capital_stock_detail.comfirm_data ='1'
and sc_mem_m_capital_stock_detail.account_year >= 2020;

